arguments.command:
# Try to use OpenRouter API with vision to analyze the image
python3 << 'EOF'
import base64, os, json
import urllib.request

# Read the image
with open('/tmp_workspace/poster_original.png', 'rb') as f:
    img_data = base64.b64encode(f.read()).decode()

base_url = os.environ.get('OPENROUTER_BASE_URL', 'http://localhost:8000/v1')
api_key = os.environ.get('OPENROUTER_API_KEY', 'dummy')

payload = {
    "model": "google/gemini-2.0-flash-001",
    "messages": [
        {
            "role": "user",
            "content": [
                {
                    "type": "image_url",
                    "image_url": {"url": f"data:image/png;base64,{img_data}"}
                },
                {
                    "type": "text",
                    "text": "Analyze this social media poster image (2746x1371 pixels, landscape). Describe: 1) The main subject/focal point and its exact position (as percentage from left/top), 2) All text content and locations, 3) Key visual elements. Most importantly: what is the BEST center point (x%, y%) to use for smart cropping to preserve the most important content? Return a JSON with: {\"focal_x_pct\": <0-100>, \"focal_y_pct\": <0-100>, \"description\": \"...\", \"important_region\": {\"left_pct\": <0-100>, \"right_pct\": <0-100>, \"top_pct\": <0-100>, \"bottom_pct\": <0-100>}}"
                }
            ]
        }
    ],
    "max_tokens": 500
}

data = json.dumps(payload).encode()
req = urllib.request.Request(
    f"{base_url}/chat/completions",
    data=data,
    headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}
)
try:
    with urllib.request.urlopen(req, timeout=60) as resp:
        result = json.loads(resp.read())
        print(json.dumps(result, indent=2))
except Exception as e:
    print(f"Error: {e}")
EOF

