python3 << 'EOF'
import base64, os, json
import urllib.request

with open('/tmp_workspace/poster_original.png', 'rb') as f:
    img_data = base64.b64encode(f.read()).decode()

# Try real openrouter.ai
api_key = os.environ.get('OPENROUTER_API_KEY', 'dummy')

payload = {
    "model": "google/gemini-2.0-flash-001",
    "messages": [
        {
            "role": "user",
            "content": [
                {
                    "type": "image_url",
                    "image_url": {"url": f"data:image/png;base64,{img_data}"}
                },
                {
                    "type": "text",
                    "text": "Analyze this social media poster image (2746x1371 pixels, landscape). What is the main subject? Where is it positioned? What text is visible and where? Give me the best focal point as percentage coordinates (focal_x_pct, focal_y_pct) from top-left for smart cropping. Return JSON only: {\"focal_x_pct\": N, \"focal_y_pct\": N, \"description\": \"...\"}"
                }
            ]
        }
    ],
    "max_tokens": 300
}

data = json.dumps(payload).encode()
req = urllib.request.Request(
    "https://openrouter.ai/api/v1/chat/completions",
    data=data,
    headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}
)
try:
    with urllib.request.urlopen(req, timeout=60) as resp:
        result = json.loads(resp.read())
        print(json.dumps(result, indent=2))
except Exception as e:
    print(f"Error: {e}")
EOF

